mapper.select:
SELECT ap.id, ap.agent_company_id, ap.property_company_id, ap.is_audited, ap.is_enabled, sc.name AS property_name, sc.code AS property_code FROM ag_company_property ap INNER JOIN sys_company sc ON ap.property_company_id = sc.id WHERE ap.agent_company_id = #{agentCode} AND sc.is_deleted = '0'
AND ap.is_enabled = #{isEnabled}
AND ap.is_audited = #{isAudited}
AND (sc.name LIKE CONCAT('%', #{searchContent}, '%') OR sc.tele LIKE CONCAT('%', #{searchContent}, '%'))
ORDER BY ap.create_time DESC

mapper.update:
UPDATE ag_company_property
SET is_audited = #{isAudited}
WHERE id = #{id}

UPDATE ag_company_property
SET is_enabled = #{isEnabled}
WHERE id = #{id}
